const rows = $json.values;
// Obtener el Lead ID de Kommo del webhook entrante
const webhookBody = $('Webhook Entrante').first().json.body;
const leadIdToFind = webhookBody["message[add][0][entity_id]"] || webhookBody["talk[add][0][entity_id]"] || "";

let contact = null;
try {
  const rawData = $('Obtener Telefono desde Kommo').item.json.data;
  contact = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
} catch (e) {}

// Obtener datos del contacto (si existen en Kommo CRM)
const emailField = contact?.custom_fields_values?.find(f => f.field_code === 'EMAIL');
const emailFromContact = (emailField?.values?.[0]?.value || "").trim().toLowerCase();

const phoneField = contact?.custom_fields_values?.find(f => f.field_code === 'PHONE');
const phoneToFind = (phoneField?.values?.[0]?.value || "").replace(/\D/g, "");

// Parsear el texto del mensaje entrante
const incomingText = webhookBody["message[add][0][text]"] || "";

// 1. Extraer Email del texto del mensaje
const emailMatches = incomingText.match(/[\w.-]+@[\w.-]+\.[a-zA-Z]+/);
const emailFromText = emailMatches ? emailMatches[0].trim().toLowerCase() : "";

// Unificar Email buscado
const emailToFind = emailFromContact || emailFromText;

// 2. Extraer Nombre y Empresa del texto del mensaje
let nombreFromText = "";
let empresaFromText = "";
const textMatch = incomingText.match(/soy\s+(.*?)\s+de\s+la\s+empresa\s+(.*?)(?:,|\.)/i);
if (textMatch) {
  nombreFromText = textMatch[1].trim().toLowerCase();
  empresaFromText = textMatch[2].trim().toLowerCase();
}

if (!rows || rows.length <= 1) {
  return []; // Parar el flujo si no hay filas
}

const headers = rows[0];
const leadIdIndex = headers.indexOf('kommo_lead_id');
const emailIndex = headers.indexOf('email');
const phoneIndex = headers.indexOf('telefono');
const nombreIndex = headers.indexOf('nombre');
const empresaIndex = headers.indexOf('empresa');
const estadoIndex = headers.indexOf('estado');
const contactIdIndex = headers.indexOf('kommo_contact_id');

// --- ESTRATEGIA 1: Buscar por Email (de abajo hacia arriba, más reciente primero) ---
if (emailToFind && emailIndex !== -1) {
  for (let i = rows.length - 1; i >= 1; i--) {
    const row = rows[i];
    const rowEmail = (row[emailIndex] || "").trim().toLowerCase();
    if (rowEmail === emailToFind) {
      return [{
        json: {
          found: true,
          rowNumber: i + 1,
          leadId: row[leadIdIndex] || leadIdToFind,
          matchType: 'email',
          telefono: phoneToFind,
          contactId: contactIdIndex !== -1 ? row[contactIdIndex] || "" : ""
        }
      }];
    }
  }
}

// --- ESTRATEGIA 2: Buscar por Nombre y Empresa (de abajo hacia arriba, más reciente primero) ---
if (nombreFromText && empresaFromText && nombreIndex !== -1 && empresaIndex !== -1) {
  for (let i = rows.length - 1; i >= 1; i--) {
    const row = rows[i];
    const rowNombre = (row[nombreIndex] || "").trim().toLowerCase();
    const rowEmpresa = (row[empresaIndex] || "").trim().toLowerCase();

    if (
      (rowNombre.includes(nombreFromText) || nombreFromText.includes(rowNombre)) &&
      (rowEmpresa.includes(empresaFromText) || empresaFromText.includes(rowEmpresa))
    ) {
      return [{
        json: {
          found: true,
          rowNumber: i + 1,
          leadId: row[leadIdIndex] || leadIdToFind,
          matchType: 'nombre_empresa',
          telefono: phoneToFind,
          contactId: contactIdIndex !== -1 ? row[contactIdIndex] || "" : ""
        }
      }];
    }
  }
}

// --- ESTRATEGIA 3: Buscar por Kommo Lead ID (de abajo hacia arriba, más reciente primero) ---
if (leadIdToFind && leadIdIndex !== -1) {
  for (let i = rows.length - 1; i >= 1; i--) {
    const row = rows[i];
    if (row[leadIdIndex] === String(leadIdToFind)) {
      return [{
        json: {
          found: true,
          rowNumber: i + 1,
          leadId: leadIdToFind,
          matchType: 'lead_id',
          telefono: phoneToFind,
          contactId: contactIdIndex !== -1 ? row[contactIdIndex] || "" : ""
        }
      }];
    }
  }
}

// --- ESTRATEGIA 4: Buscar por Teléfono (normalizado, de abajo hacia arriba, más reciente primero) ---
if (phoneToFind && phoneIndex !== -1) {
  for (let i = rows.length - 1; i >= 1; i--) {
    const row = rows[i];
    const rowPhone = (row[phoneIndex] || "").replace(/\D/g, "");
    if (rowPhone && (rowPhone === phoneToFind || phoneToFind.endsWith(rowPhone) || rowPhone.endsWith(phoneToFind))) {
      return [{
        json: {
          found: true,
          rowNumber: i + 1,
          leadId: row[leadIdIndex] || leadIdToFind,
          matchType: 'phone',
          telefono: phoneToFind,
          contactId: contactIdIndex !== -1 ? row[contactIdIndex] || "" : ""
        }
      }];
    }
  }
}

// --- ESTRATEGIA 5: Fallback al último lead en "esperando_chat" (de abajo hacia arriba) ---
if (estadoIndex !== -1) {
  for (let i = rows.length - 1; i >= 1; i--) {
    const row = rows[i];
    const rowEstado = (row[estadoIndex] || "").trim().toLowerCase();
    const rowPhone = (row[phoneIndex] || "").trim();
    if (rowEstado === 'esperando_chat' && !rowPhone) {
      return [{
        json: {
          found: true,
          rowNumber: i + 1,
          leadId: row[leadIdIndex] || leadIdToFind,
          matchType: 'fallback_esperando_chat',
          telefono: phoneToFind,
          contactId: contactIdIndex !== -1 ? row[contactIdIndex] || "" : ""
        }
      }];
    }
  }
}

return []; // Detener el flujo si no se encuentra nada
